```class Solution:
    def originalDigits(self, s: str) -> str:
        count = {}
        for c in s:
            count[c] = count.get(c, 0) + 1
        digits = ["zero", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine"]
        letters = ["z", "o", "t", "h", "f", "v", "x", "s", "g", "e"]
        result = [0] * 10
        for i in range(10):
            for c in letters[i]:
                if count.get(c, 0) < result[i]:
                    break
                result[i] -= count.get(c, 0)
            if result[i] == 0:
                return "".join(str(i) for i in range(10) if result[i] > 0)
        return "".join(str(i) for i in range(10) if result[i] > 0)
